+        }
+
+        stage('Test') {
+            steps {
+                echo '✅ Running unit tests...'
+                sh '. $VENV_DIR/bin/activate && pytest'
+            }
+        }
+
+        stage('Deploy') {
+            steps {
+                echo '🚀 Deploying Flask app...'
+                sh '. $VENV_DIR/bin/activate && nohup python app.py &'
+            }
+        }
+    }
+
+    post {
+        success {
+            echo '✅ Build and deployment successful!'
+        }
+        failure {
+            echo '❌ Build or tests failed. Check logs.'
